SELECT AVG(("dropoff_datetime" - "pickup_datetime") / 1000000 / 60) AS "average_trip_duration_minutes" FROM "NEW_YORK_PLUS"."NEW_YORK_TAXI_TRIPS"."TLC_YELLOW_TRIPS_2016" "trips" INNER JOIN "NEW_YORK_PLUS"."NEW_YORK_TAXI_TRIPS"."TAXI_ZONE_GEOM" "pickup_zone" ON "trips"."pickup_location_id" = "pickup_zone"."zone_id" INNER JOIN "NEW_YORK_PLUS"."NEW_YORK_TAXI_TRIPS"."TAXI_ZONE_GEOM" "dropoff_zone" ON "trips"."dropoff_location_id" = "dropoff_zone"."zone_id" WHERE DATE(TO_TIMESTAMP("pickup_datetime" / 1000000)) BETWEEN DATE '2016-02-01' AND DATE '2016-02-07' AND "dropoff_datetime" > "pickup_datetime" AND "passenger_count" > 3 AND "trip_distance" >= 10 AND "pickup_zone"."borough" = 'Brooklyn' AND "dropoff_zone"."borough" = 'Brooklyn'